  // Check 1: Count real images in colonial section
  const colonial = document.getElementById('periodo-colonial');
  const cardImages = colonial.querySelectorAll('.card-image img');
  const cardPlaceholders = colonial.querySelectorAll('.card-image-placeholder');

  // Check 2: All images have non-empty alt text
  const allHaveAlt = Array.from(cardImages).every(img => img.getAttribute('alt') && img.getAttribute('alt').length > 10);

  // Check 3: All images have loading="lazy"
  const allLazy = Array.from(cardImages).every(img => img.getAttribute('loading') === 'lazy');

  // Check 4: All images have Wikimedia URLs
  const allWikimedia = Array.from(cardImages).every(img => img.src.includes('wikimedia.org'));

  // Check 5: Card image CSS exists
  const testEl = document.querySelector('.card-image');
  const computedStyle = testEl ? window.getComputedStyle(testEl) : null;
  const hasOverflowHidden = computedStyle ? computedStyle.overflow === 'hidden' : false;
  const hasMaxHeight = computedStyle ? computedStyle.maxHeight === '220px' : false;

  // Check 6: Fallback CSS class exists (test the styles)
  const sheet = document.styleSheets[1]; // styles.css
  let hasFallbackCSS = false;
  try {
    for (const rule of sheet.cssRules) {
      if (rule.selectorText && rule.selectorText.includes('img-fallback')) {
        hasFallbackCSS = true;
        break;
      }
    }
  } catch(e) { hasFallbackCSS = 'error checking'; }

  return {
    realImagesCount: cardImages.length,
    placeholdersCount: cardPlaceholders.length,
    allHaveAlt,
    allLazy,
    allWikimedia,
    hasOverflowHidden,
    hasMaxHeight,
    hasFallbackCSS,
    imageUrls: Array.from(cardImages).map(img => img.src.split('/').pop()),
    altTexts: Array.from(cardImages).map(img => img.getAttribute('alt').substring(0, 50) + '...')
  };
})()

